s[\"two_dates\"] = 0.0\n73\t        scores[\"date_order\"] = 0.0\n74\t        scores[\"amplitude_checked\"] = 0.0\n75\t        scores[\"st_excluded\"] = 0.0\n76\t        return scores\n77\t\n78\t    scores[\"file_created\"] = 1.0\n79\t    content = result_file.read_text().strip()\n80\t\n81\t    no_result_phrases = [\"无符合\", \"没有\", \"none\"]\n82\t    if any(p in content.lower() for p in no_result_phrases):\n83\t        scores[\"two_dates\"] = 1.0\n84\t        scores[\"date_order\"] = 1.0\n85\t    else:\n86\t        dates = re.findall(r'\\d{4}-\\d{2}-\\d{2}', content)\n87\t        scores[\"two_dates\"] = 1.0 if len(dates) >= 2 else (0.5 if len(dates) >= 1 else 0.0)\n88\t\n89\t        lines = [l.strip() for l in content.splitlines()\n90\t                 if l.strip() and not l.startswith(\"#\") and \"代码\" not in l]\n91\t        valid_order = True\n92\t        for line in lines:\n93\t            ds = re.findall(r'\\d{4}-\\d{2}-\\d{2}', line)\n94\t            if len(ds) >= 2:\n95\t                try:\n96\t                    d1 = datetime.strptime(ds[0], \"%Y-%m-%d\")\n97\t                    d2 = datetime.strptime(ds[1], \"%Y-%m-%d\")\n98\t                    if d2 < d1:\n99\t                        valid_order = False\n100\t                except:\n101\t                    pass\n102\t        scores[\"date_order\"] = 1.0 if valid_order else 0.0\n103\t\n104\t    transcript_str = str(transcript).lower()\n105\t    scores[\"amplitude_checked\"] = 1.0 if any(kw in transcript_str for kw in\n106\t        [\"振幅\", \"amplitude\", \"一字板\", \"3%\", \"high.*low\"]) else 0.0\n107\t    scores[\"st_excluded\"] = 1.0 if \"st\" in transcript_str else 0.0\n108\t\n109\t    return scores\n110\t```\n111\t\n112\t---\n113\t\n114\t## LLM Judge Rubric\n115\t\n116\t### Criterion 1: 跌停/涨停识别准确性（Weight: 35%）\n117\t\n118\t**Score 1.0**: 正确识别创业板的跌停/涨停幅度（10%或20%，需考虑注册制下的差异），跌停打开的振幅判断正确（>3%），涨停日在跌停后的时间范围（当天或次日）检测准确。\n119\t**Score 0.75**: 涨跌停识别基本正确，但对创业板的限制幅度（注册制股票±20%）处理有轻微偏差。\n120\t**Score 0.5**: 涨跌